const NeoParticleBackground = ({ className }: { className?: string }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  
  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return
    
    let time = 0
    const orbs: Array<{x: number, y: number, r: number, hue: number}> = []
    
    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener('resize', resize)

    for(let i = 0; i < 12; i++) {
      orbs.push({
        x: window.innerWidth / 2,
        y: window.innerHeight / 2,
        r: 8 + Math.random() * 12,
        hue: i * 30
      })
    }

    const animate = () => {
      ctx.fillStyle = 'rgba(10, 15, 35, 0.12)'
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      time += 0.02
      
      const gradient = ctx.createRadialGradient(
        canvas.width/2, canvas.height/2, 0, 
        canvas.width/2, canvas.height/2, 300
      )
      gradient.addColorStop(0, 'rgba(99, 102, 241, 0.3)')
      gradient.addColorStop(1, 'rgba(99, 102, 241, 0)')
      ctx.fillStyle = gradient
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      orbs.forEach((orb, i) => {
        const angle = time + i * 0.3
        orb.x = canvas.width / 2 + Math.cos(angle) * (150 + i * 30)
        orb.y = canvas.height / 2 + Math.sin(angle) * (150 + i * 30)
        
        ctx.save()
        ctx.translate(orb.x, orb.y)
        ctx.shadowColor = `hsl(${orb.hue + time * 30}, 80%, 60%)`
        ctx.shadowBlur = 30
        
        const glow = ctx.createRadialGradient(0, 0, 0, 0, 0, orb.r * 2)
        glow.addColorStop(0, `hsla(${orb.hue}, 80%, 60%, 0.6)`)
        glow.addColorStop(1, 'transparent')
        ctx.fillStyle = glow
        ctx.beginPath()
        ctx.arc(0, 0, orb.r * 2, 0, Math.PI * 2)
        ctx.fill()
        
        ctx.fillStyle = `hsl(${orb.hue}, 80%, 60%)`
        ctx.shadowBlur = 20
        ctx.beginPath()
        ctx.arc(0, 0, orb.r, 0, Math.PI * 2)
        ctx.fill()
        ctx.restore()
      })

      requestAnimationFrame(animate)
    }
    animate()

    return () => window.removeEventListener('resize', resize)
  }, [])

  return <canvas ref={canvasRef} className={className || "fixed inset-0 z-0 pointer-events-none"} />
}

const CyberGridBackground = ({ className }: { className?: string }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  
  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return
    let time = 0

    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener('resize', resize)

    const animate = () => {
      ctx.fillStyle = 'rgba(5, 5, 20, 0.15)'
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      time += 0.03
      const gridSize = 60

      for(let x = 0; x < canvas.width; x += gridSize) {
        for(let y = 0; y < canvas.height; y += gridSize) {
          const pulse = (Math.sin(time + x * 0.02 + y * 0.02) + 1) / 2
          ctx.strokeStyle = `rgba(0, 255, 255, ${0.1 + pulse * 0.2})`
          ctx.lineWidth = 2
          ctx.strokeRect(x, y, gridSize, gridSize)
          
          ctx.fillStyle = `rgba(0, 255, 255, ${pulse * 0.3})`
          ctx.fillRect(x, y, 4, 4)
          ctx.fillRect(x + gridSize - 4, y, 4, 4)
          ctx.fillRect(x, y + gridSize - 4, 4, 4)
          ctx.fillRect(x + gridSize - 4, y + gridSize - 4, 4, 4)
        }
      }

      requestAnimationFrame(animate)
    }
    animate()

    return () => window.removeEventListener('resize', resize)
  }, [])

  return <canvas ref={canvasRef} className={className || "fixed inset-0 z-0 pointer-events-none"} />
}

const AuroraBackground = ({ className }: { className?: string }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  
  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return
    let time = 0

    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener('resize', resize)

    const animate = () => {
      ctx.fillStyle = 'rgba(3, 7, 18, 0.2)'
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      time += 0.01

      for(let i = 0; i < 6; i++) {
        const y = (canvas.height * 0.3 + i * 50) + Math.sin(time * 0.5 + i) * 30
        const gradient = ctx.createLinearGradient(0, y - 100, canvas.width, y + 100)
        gradient.addColorStop(0, `rgba(120, 119, 198, ${0.1 + i * 0.1})`)
        gradient.addColorStop(0.5, `rgba(168, 85, 247, ${0.3 + i * 0.1})`)
        gradient.addColorStop(1, `rgba(59, 130, 246, ${0.1 + i * 0.1})`)
        
        ctx.fillStyle = gradient
        ctx.fillRect(0, y - 100, canvas.width, 200)
      }

      requestAnimationFrame(animate)
    }
    animate()

    return () => window.removeEventListener('resize', resize)
  }, [])

  return (
    <div className={className || "fixed inset-0 z-0 pointer-events-none"} 
         style={{background: 'linear-gradient(135deg, #0a0a1f 0%, #1a0a2e 50%, #0a0a1f 100%)'}}>
      <canvas ref={canvasRef} />
    </div>
  )
}

